class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int n = s.size();
        for (int l = (n % 2 == 0) ? n : n - 1; l >= 0; l -= 2) {
            if (l == 0) {
                return 0;
            }
            for (int i = 0; i <= n - l; ++i) {
                string substr = s.substr(i, l);
                bool seen_one = false;
                int zeros = 0;
                bool valid = true;
                for (char c : substr) {
                    if (c == '0') {
                        if (seen_one) {
                            valid = false;
                            break;
                        }
                        zeros++;
                    } else {
                        seen_one = true;
                    }
                }
                if (valid && zeros == (l / 2)) {
                    return l;
                }
            }
        }
        return 0;
    }
};

